Future<void> fetchWeather(String city) async {
  state = const AsyncValue.loading();
  try {
    final response = await http.get(Uri.parse('https://api.openweathermap.org/data/2.5/weather?q=$city&appid=key'));
    if (response.statusCode == 200) {
      final weather = Weather.fromJson(jsonDecode(response.body));
      state = AsyncValue.data(weather);
    } else {
      state = AsyncValue.error('Erreur serveur', StackTrace.current);
    }
  } catch (e, st) {
    state = AsyncValue.error(e, st);
  }
}
